// Workflow Name: "OAuth-MCP-Validator"
// Trigger: "Execute Workflow"

const crypto = require('crypto');

try {
    // Input von MCP-Request
    const authHeader = $input.first().json.authorization;

    if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return [{
            json: {
                error: "Authentication required",
                code: 401
            }
        }];
    }

    const token = authHeader.substring(7);
    const jwtSecret = $env.JWT_SECRET;

    // JWT-Validation (vereinfacht)
    const tokenParts = token.split('.');
    if (tokenParts.length !== 3) {
        return [{
            json: {
                error: "Invalid token format",
                code: 401
            }
        }];
    }

    // Signature prüfen
    const signatureInput = `${tokenParts[0]}.${tokenParts[1]}`;
    const expectedSignature = crypto
        .createHmac('sha256', jwtSecret)
        .update(signatureInput)
        .digest('base64url');

    if (expectedSignature !== tokenParts[2]) {
        return [{
            json: {
                error: "Invalid token",
                code: 401
            }
        }];
    }

    // Success
    const payload = JSON.parse(Buffer.from(tokenParts[1], 'base64url').toString());

    return [{
        json: {
            validated: true,
            client_id: payload.client_id,
            scopes: payload.scope.split(' ')
        }
    }];

} catch (error) {
    return [{
        json: {
            error: "Authentication failed",
            code: 500
        }
    }];
}
